<section class="v4-page-shell"><div class="v4-page-head"><h1>Media Trash Restore</h1><p>الملفات المؤرشفة داخل <code>storage/trash/media</code> يمكن استعادتها بدل حذفها نهائيًا.</p></div>
<?php if (!empty($flash)): ?><div class="v4-flash v4-flash-<?= e($flash['type'] ?? 'info') ?>"><?= e($flash['message'] ?? '') ?></div><?php endif; ?>
<?php $archived = array_values(array_filter(($rows ?? []), fn($r) => ($r['status'] ?? '') === 'archived')); ?>
<?php if (!empty($archived)): ?><div class="v4-table-wrap"><table class="v4-table"><thead><tr><th>المسار الأصلي</th><th>Trash Path</th><th>تاريخ الأرشفة</th><th>إجراء</th></tr></thead><tbody><?php foreach ($archived as $row): ?><tr><td><code><?= e($row['path'] ?? '') ?></code></td><td><code><?= e($row['trash_path'] ?? '') ?></code></td><td><?= e($row['archived_at'] ?? '') ?></td><td><form class="v4-inline-form" method="post" action="<?= e(godyar_v4_base_url('/v4/admin/media-trash/restore')) ?>"><?= godyar_v4_csrf_field() ?><input type="hidden" name="path" value="<?= e($row['path'] ?? '') ?>"><button type="submit" class="v4-btn-ghost">استعادة</button></form></td></tr><?php endforeach; ?></tbody></table></div><?php else: ?><div class="v4-empty-state"><p>لا توجد ملفات مؤرشفة حاليًا.</p></div><?php endif; ?></section>
